### Expose RxStorage in SharedWorker (TypeScript)

Source: https://github.com/pubkey/rxdb/blob/master/docs/rx-storage-shared-worker.html

This snippet demonstrates how to expose an RxStorage instance within a SharedWorker using RxDB. It imports necessary functions, sets up the IndexedDB storage, and then exposes it to be used by other RxDB instances. Dependencies include 'rxdb-premium/plugins/storage-worker', 'rxdb-premium/plugins/storage-indexeddb', 'rxdb', and 'rxdb/plugins/replication-graphql'.

```typescript
// shared-worker.ts
import { exposeWorkerRxStorage } from 'rxdb-premium/plugins/storage-worker';
import { getRxStorageIndexedDB } from 'rxdb-premium/plugins/storage-indexeddb';
import { createRxDatabase, addRxPlugin } from 'rxdb';
import { RxDBReplicationGraphQLPlugin } from 'rxdb/plugins/replication-graphql';

addRxPlugin(RxDBReplicationGraphQLPlugin);

const baseStorage = getRxStorageIndexedDB();

// first expose the RxStorage to the outside
exposeWorkerRxStorage({
    storage: baseStorage
});

/**
 * Then create a normal RxDatabase and RxCollections
 * and start the replication.
 */
const database = await createRxDatabase({
    name: 'mydatabase',
    storage: baseStorage
});

await db.addCollections({
    humans: { /* ... */ }
});

const replicationState = db.humans.syncGraphQL({ /* ... */ });
```

